#!/bin/bash
set -e
cd "$(dirname "$0")"

mkdir -p components/affiliates
python3 -c "import base64; open('components/affiliates/affiliate-card.tsx', 'wb').write(base64.b64decode(''))"
echo "✅ components/affiliates/affiliate-card.tsx"

mkdir -p components/calculators
python3 -c "import base64; open('components/calculators/overtime-calculator.tsx', 'wb').write(base64.b64decode(''))"
echo "✅ components/calculators/overtime-calculator.tsx"

mkdir -p scripts
python3 -c "import base64; open('scripts/generate-article.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/generate-article.mjs"

mkdir -p scripts
python3 -c "import base64; open('scripts/run-pipeline.sh', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/run-pipeline.sh"

mkdir -p scripts
python3 -c "import base64; open('scripts/analyze-and-improve.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/analyze-and-improve.mjs"

mkdir -p scripts
python3 -c "import base64; open('scripts/SETUP.md', 'wb').write(base64.b64decode(''))"
echo "✅ scripts/SETUP.md"

git add -A
git status --short
git commit -m "feat: GA4 affiliate tracking + dynamic CTA + full automation pipeline

- affiliate-card.tsx: affiliate_click event on every CTA (GA4)
- overtime-calculator.tsx: dynamic CTA when result > 0
- scripts/generate-article.mjs: Claude API article pipeline
- scripts/run-pipeline.sh: cron wrapper
- scripts/analyze-and-improve.mjs: GSC→Claude→auto-improve
- scripts/SETUP.md: setup guide"
git push origin main
echo ""
echo "🚀 Push完了！Vercelデプロイ開始"
echo ""
echo "=== 次のステップ ==="
echo "1. .env.local にGSCキーを設定:"
echo "   GSC_CLIENT_EMAIL=affiliate-gsc-bot@secretary-ai-492700.iam.gserviceaccount.com"
echo "   GSC_PRIVATE_KEY=<ダウンロードしたJSONのprivate_key>"
echo ""
echo "2. テスト実行:"
echo "   node scripts/generate-article.mjs --dry-run"
echo "   node scripts/analyze-and-improve.mjs --report-only"
echo ""
echo "3. cron設定 (crontab -e):"
echo "   0 8 * * 1,4 cd ~/Downloads/kyuryo-lab && bash scripts/run-pipeline.sh >> scripts/pipeline.log 2>&1"
echo "   0 9 * * 0 cd ~/Downloads/kyuryo-lab && node scripts/analyze-and-improve.mjs >> scripts/analysis.log 2>&1"